{"parentUuid":"d63bb744-af96-4847-931d-5edd26382263","isSidechain":true,"promptId":"67a32f7f-bdb0-4fe2-93c8-5e5b811f2642","agentId":"a67b13a577b101f29","type":"user","message":{"role":"user","content":[{"tool_use_id":"REDACTED","type":"tool_result","content":"     1→/**
     2→ * In-memory template definition registry.
     3→ *
     4→ * Code-defined templates register their header, defaultBody, variables, and category here
     5→ * at module load time. The DB layer (prompt_templates table) stores runtime overrides.
     6→ */
     7→
     8→export interface VariableDefinition {
     9→  name: string;
    10→  description: string;
    11→  example?: string;
    12→}
    13→
    14→export interface EventTemplateDefinition {
    15→  /** Dot-separated event identifier, e.g. "github.pull_request.review_submitted" */
    16→  eventType: string;
    17→  /** Always-on prefix (code-defined, not overridable), uses {{var}} syntax */
    18→  header: string;
    19→  /** Hardcoded fallback body used when no DB override exists */
    20→  defaultBody: string;
    21→  /** Variable definitions for documentation and validation */
    22→  variables: VariableDefinition[];
    23→  /** Category for grouping in the UI */
    24→  category: "event" | "system" | "common" | "task_lifecycle" | "session";
    25→}
    26→
    27→const templateDefinitions = new Map<string, EventTemplateDefinition>();
    28→
    29→/**
    30→ * Register a template definition in the in-memory registry.
    31→ * Called at module load time by event handler modules.
    32→ */
    33→export function registerTemplate(def: EventTemplateDefinition): void {
    34→  templateDefinitions.set(def.eventType, def);
    35→}
    36→
    37→/**
    38→ * Look up a template definition by eventType.
    39→ */
    40→export function getTemplateDefinition(eventType: string): EventTemplateDefinition | undefined {
    41→  return templateDefinitions.get(eventType);
    42→}
    43→
    44→/**
    45→ * Return all registered template definitions.
    46→ */
    47→export function getAllTemplateDefinitions(): EventTemplateDefinition[] {
    48→  return Array.from(templateDefinitions.values());
    49→}
    50→
    51→/**
    52→ * Clear all registered template definitions.
    53→ * Only used in tests to reset state between runs.
    54→ */
    55→export function clearTemplateDefinitions(): void {
    56→  templateDefinitions.clear();
    57→}
    58→"}]},"uuid":"13bec355-aba5-4a4f-8e61-5c4a6c1bd3b8","timestamp":"2026-03-21T15:18:31.473Z","sourceToolAssistantUUID":"d63bb744-af96-4847-931d-5edd26382263","userType":"external","entrypoint":"cli","cwd":"/Users/taras/worktrees/agent-swarm/2026-03-20-fet/template-registry","sessionId":"178611d1-0106-48bf-921c-64d57816552b","version":"2.1.80","gitBranch":"fet/template-registry","slug":"synchronous-dazzling-cloud"}
