     9→ */
    10→
    11→import { resolvePromptTemplate } from "../be/db";
    12→import { interpolate } from "../workflows/template";
    13→import { getTemplateDefinition } from "./registry";
    14→
    15→export interface ResolveOptions {
    16→  agentId?: string;
    17→  repoId?: string;
    18→}
    19→
    20→export interface ResolveResult {
    21→  /** Final resolved text (header + body, interpolated) */
    22→  text: string;
    23→  /** Which DB template was used (undefined if hardcoded default) */
    24→  templateId?: string;
    25→  /** Which scope level matched */
    26→  scope?: string;
    27→  /** true if skip_event was triggered */
    28→  skipped: boolean;
    29→  /** Any {{var}} tokens that couldn't be resolved */
    30→  unresolved: string[];
    31→}
