    33→// ─── HTTP Resolver Mode ─────────────────────────────────────────────────────
    34→
    35→interface HttpResolverConfig {
    36→  apiUrl: string;
    37→  apiKey: string;
    38→}
    39→
    40→let httpResolverConfig: HttpResolverConfig | null = null;
    41→
    42→/**
    43→ * Configure the resolver to use HTTP mode (for Docker workers).
    44→ * Once configured, all resolveTemplate() calls go through the API server
