  body: z.object({
    eventType: z.string(),
    variables: z.record(z.string(), z.unknown()).optional(),
    agentId: z.string().optional(),
    repoId: z.string().optional(),
  }),
  responses: {
    200: { description: "Fully resolved and interpolated template" },
    400: { description: "Validation error" },
  },
  auth: { apiKey: true },
});

