 88→  const renderMutate = renderMutation.mutate;
 89→  // biome-ignore lint/correctness/useExhaustiveDependencies: templateVersion triggers re-render after save/checkout/reset
 90→  useEffect(() => {
 91→    if (!templateEventType) return;
 92→    const sampleVars: Record<string, string> = {};
 93→    const eventDef = events?.find((e) => e.eventType === templateEventType);
 94→    if (eventDef) {
 95→      for (const v of eventDef.variables) {
 96→        sampleVars[v.name] = v.example ?? v.name;
 97→      }
 98→    }
 99→    renderMutate(
100→      { eventType: templateEventType, variables: sampleVars },
101→      {
102→        onSuccess: (result) => {
103→          setRendered(result.text);
104→          setUnresolved(result.unresolved);
105→        },
106→      },
107→    );
108→  }, [templateEventType, templateVersion, events, renderMutate]);
109→
110→  const handleSave = useCallback(() => {
111→    if (!template) return;
112→    upsertMutation.mutate(
113→      {
114→        eventType: template.eventType,
115→        body,
116→        state: state as "enabled" | "default_prompt_fallback" | "skip_event",
117→        scope: template.scope,
118→        scopeId: template.scopeId ?? undefined,
119→      },
120→      {
121→        onSuccess: () => toast.success("Template saved"),
122→        onError: () => toast.error("Failed to save template"),
123→      },
124→    );
125→  }, [template, body, state, upsertMutation]);
126→
127→  const handleCustomize = useCallback(() => {
128→    if (!template) return;
129→    upsertMutation.mutate(
130→      {
131→        eventType: template.eventType,
132→        body: template.body,
133→        scope: "global",
134→      },
135→      {
136→        onSuccess: () => toast.success("Template customized — you can now edit it"),
137→        onError: () => toast.error("Failed to customize template"),
138→      },
139→    );
140→  }, [template, upsertMutation]);
141→
142→  const handleDelete = useCallback(() => {
143→    if (!id) return;
144→    deleteMutation.mutate(id, {
145→      onSuccess: () => {
146→        toast.success("Template deleted");
147→        navigate("/templates");
148→      },
149→      onError: () => toast.error("Failed to delete template"),
150→    });
151→  }, [id, deleteMutation, navigate]);
152→
153→  const handleReset = useCallback(() => {
154→    if (!id) return;
155→    resetMutation.mutate(id, {
156→      onSuccess: () => toast.success("Template reset to default"),
157→      onError: () => toast.error("Failed to reset template"),
158→    });
159→    setResetOpen(false);
160→  }, [id, resetMutation]);
161→
162→  const handleCheckout = useCallback(() => {
163→    if (!id || checkoutVersion === null) return;
164→    const ver = checkoutVersion;
165→    checkoutMutation.mutate(
166→      { id, version: ver },
167→      {
168→        onSuccess: () => toast.success(`Checked out version ${ver}`),
169→        onError: () => toast.error("Failed to checkout version"),
170→      },
171→    );
172→    setCheckoutVersion(null);
173→  }, [id, checkoutVersion, checkoutMutation]);
174→
175→  // Cmd+S / Ctrl+S to save (non-default templates only)
176→  const isDefault = template?.isDefault;
177→  useEffect(() => {
178→    const handleKeyDown = (e: KeyboardEvent) => {
179→      if ((e.metaKey || e.ctrlKey) && e.key === "s") {
180→        e.preventDefault();
181→        if (!isDefault) {
182→          handleSave();
183→        }
184→      }
185→    };
186→    window.addEventListener("keydown", handleKeyDown);
187→    return () => window.removeEventListener("keydown", handleKeyDown);
188→  }, [isDefault, handleSave]);
189→
190→  const eventDef = useMemo(
191→    () => events?.find((e) => e.eventType === template?.eventType),
192→    [events, template?.eventType],
193→  );
194→
195→  // History grid columns
196→  const historyColumns = useMemo<ColDef<PromptTemplateHistory>[]>(
197→    () => [
198→      { field: "version", headerName: "Version", width: 90 },
199→      {
200→        field: "state",
201→        headerName: "State",
202→        width: 180,
203→        cellRenderer: (params: { value: string }) => (
204→          <Badge
205→            variant={STATE_VARIANTS[params.value] ?? "outline"}
206→            className="text-[9px] px-1.5 py-0 h-5 font-medium leading-none items-center uppercase"
207→          >
208→            {params.value?.replace(/_/g, " ")}
209→          </Badge>
210→        ),
211→      },
212→      { field: "changedBy", headerName: "Changed By", flex: 1, minWidth: 120 },
213→      {
214→        field: "changedAt",
215→        headerName: "Changed At",
216→        width: 150,
217→        valueFormatter: (params) => (params.value ? formatSmartTime(params.value) : ""),
218→      },
219→      {
220→        field: "changeReason",
221→        headerName: "Reason",
222→        flex: 1,
223→        minWidth: 150,
224→      },
225→      {
226→        headerName: "",
227→        width: 100,
228→        cellRenderer: (params: { data: PromptTemplateHistory | undefined }) => {
229→          if (!params.data) return null;
230→          return (
231→            <Button
232→              variant="outline"
233→              size="sm"
234→              className="h-6 text-xs"
235→              onClick={(e) => {
236→                e.stopPropagation();
237→                setCheckoutVersion(params.data!.version);
238→              }}
239→            >
240→              Checkout
241→            </Button>
242→          );
243→        },
244→        sortable: false,
245→      },
246→    ],
247→    [],
248→  );
249→
250→  const onHistoryRowClicked = useCallback(
251→    (event: RowClickedEvent<PromptTemplateHistory>) => {
252→      if (event.data) {
253→        navigate(`/templates/${id}/history/${event.data.version}`);
254→      }
255→    },
256→    [navigate, id],
257→  );
258→
259→  if (isLoading) {
260→    return (
261→      <div className="space-y-4">
262→        <Skeleton className="h-8 w-64" />
263→        <Skeleton className="h-48 w-full" />
264→      </div>
265→    );
266→  }
267→
268→  if (isError || !template) {
269→    return (
270→      <div className="flex flex-col flex-1 items-center justify-center gap-2 text-muted-foreground">
271→        <p>Template not found</p>
272→        <Button variant="outline" size="sm" asChild>
273→          <Link to="/templates">Back to Templates</Link>
274→        </Button>
275→      </div>
276→    );
277→  }
278→
279→  return (
280→    <div className="flex flex-col flex-1 min-h-0 gap-4">
281→      {/* Header */}
282→      <div className="flex flex-col gap-3">
283→        <button
284→          type="button"
285→          onClick={() => navigate("/templates")}
286→          className="flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground transition-colors w-fit"
287→        >
288→          <ArrowLeft className="h-4 w-4" /> Back to Templates
289→        </button>
290→
291→        <div className="flex items-center gap-3 flex-wrap">
292→          <h1 className="text-xl font-semibold">{template.eventType}</h1>
293→          <Badge
294→            variant="outline"
295→            className="text-[9px] px-1.5 py-0 h-5 font-medium leading-none items-center uppercase"
296→          >
297→            {template.scope}
298→          </Badge>
299→          <Badge
300→            variant={STATE_VARIANTS[template.state] ?? "outline"}
301→            className="text-[9px] px-1.5 py-0 h-5 font-medium leading-none items-center uppercase"
302→          >
303→            {template.state.replace(/_/g, " ")}
304→          </Badge>
305→          <Badge
306→            variant="outline"
307→            className="text-[9px] px-1.5 py-0 h-5 font-medium leading-none items-center uppercase"
308→          >
309→            v{template.version}
310→          </Badge>
311→          {template.isDefault && (
312→            <Badge
313→              variant="secondary"
314→              className="text-[9px] px-1.5 py-0 h-5 font-medium leading-none items-center uppercase"
315→            >
316→              Default
317→            </Badge>
318→          )}
319→
320→          {!template.isDefault && (
321→            <div className="ml-auto">
322→              <Button
323→                variant="outline"
324→                size="sm"
325→                className="border-red-500/30 text-red-400 hover:bg-red-500/10"
326→                onClick={() => setDeleteOpen(true)}
327→              >
328→                Delete
329→              </Button>
330→            </div>
331→          )}
332→        </div>
333→      </div>
334→
335→      {/* Tabs */}
336→      <Tabs defaultValue="raw" className="flex flex-col flex-1 min-h-0">
337→        <TabsList>
338→          <TabsTrigger value="raw">Raw</TabsTrigger>
339→          <TabsTrigger value="rendered">Rendered</TabsTrigger>
340→          <TabsTrigger value="history">History</TabsTrigger>
341→        </TabsList>
342→
343→        {/* Raw Tab */}
344→        <TabsContent value="raw" className="flex flex-col flex-1 min-h-0 gap-3">
345→          {template.isDefault ? (
346→            <>
347→              <div className="flex items-center gap-2">
348→                <Badge
349→                  variant="secondary"
350→                  className="text-[9px] px-1.5 py-0 h-5 font-medium leading-none items-center uppercase"
351→                >
352→                  Default — Read Only
353→                </Badge>
354→                <Button variant="outline" size="sm" onClick={handleCustomize}>
355→                  Customize
356→                </Button>
357→              </div>
358→              <div className="flex-1 min-h-0 border border-border rounded-md overflow-hidden">
359→                <Editor
360→                  language="markdown"
361→                  theme={theme === "dark" ? "vs-dark" : "vs"}
362→                  value={template.body}
363→                  options={{
364→                    readOnly: true,
365→                    minimap: { enabled: false },
366→                    scrollBeyondLastLine: false,
367→                    fontSize: 13,
368→                    lineNumbers: "on",
369→                    wordWrap: "on",
370→                    automaticLayout: true,
371→                    padding: { top: 8 },
372→                  }}
373→                  height="100%"
374→                />
375→              </div>
376→            </>
377→          ) : (
378→            <>
379→              <div className="flex items-center gap-3">
380→                <Select value={state} onValueChange={setState}>
381→                  <SelectTrigger className="w-[220px]">
382→                    <SelectValue />
383→                  </SelectTrigger>
384→                  <SelectContent>
385→                    <SelectItem value="enabled">Enabled</SelectItem>
386→                    <SelectItem value="default_prompt_fallback">Default Prompt Fallback</SelectItem>
387→                    <SelectItem value="skip_event">Skip Event</SelectItem>
388→                  </SelectContent>
389→                </Select>
390→                <Button
391→                  size="sm"
392→                  onClick={handleSave}
393→                  disabled={upsertMutation.isPending}
394→                  className="bg-primary hover:bg-primary/90"
395→                >
396→                  {upsertMutation.isPending ? "Saving..." : "Save"}
397→                </Button>
398→                <Button variant="outline" size="sm" onClick={() => setResetOpen(true)}>
399→                  Reset
400→                </Button>
401→              </div>
402→              <div className="flex-1 min-h-0 border border-border rounded-md overflow-hidden">
403→                <Editor
404→                  language="markdown"
405→                  theme={theme === "dark" ? "vs-dark" : "vs"}
406→                  value={body}
407→                  onChange={(value) => setBody(value ?? "")}
408→                  options={{
409→                    minimap: { enabled: false },
410→                    scrollBeyondLastLine: false,
411→                    fontSize: 13,
412→                    lineNumbers: "on",
413→                    wordWrap: "on",
414→                    automaticLayout: true,
415→                    padding: { top: 8 },
416→                  }}
417→                  height="100%"
418→                />
419→              </div>
420→            </>
421→          )}
422→        </TabsContent>
423→
424→        {/* Rendered Tab */}
425→        <TabsContent value="rendered" className="flex-1 overflow-auto">
426→          <div className="space-y-4">
427→            {(() => {
428→              const templateRefs = unresolved.filter((v) => v.startsWith("@template["));
429→              const regularVars = unresolved.filter((v) => !v.startsWith("@template["));
430→              const hasContent = rendered.trim().length > 0;
431→              return (
432→                <>
433→                  {templateRefs.length > 0 && (
434→                    <div className="flex items-start gap-2 rounded-md border border-border bg-muted/50 p-3">
435→                      <Info className="h-4 w-4 text-muted-foreground shrink-0 mt-0.5" />
436→                      <div className="space-y-2">
437→                        <p className="text-xs text-muted-foreground">
438→                          This template includes composition references that are resolved at
439→                          runtime:
440→                        </p>
441→                        <div className="flex items-center gap-1.5 flex-wrap">
442→                          {templateRefs.map((v) => (
443→                            <Badge
444→                              key={v}
445→                              variant="outline"
446→                              className="text-[9px] px-1.5 py-0 h-5 font-medium leading-none items-center border-muted-foreground/30 text-muted-foreground"
447→                            >
448→                              {v}
449→                            </Badge>
450→                          ))}
451→                        </div>
452→                      </div>
453→                    </div>
454→                  )}
455→                  {regularVars.length > 0 && (
456→                    <div className="flex items-center gap-2 flex-wrap">
457→                      <span className="text-xs text-muted-foreground">Unresolved variables:</span>
458→                      {regularVars.map((v) => (
459→                        <Badge
460→                          key={v}
461→                          variant="outline"
462→                          className="text-[9px] px-1.5 py-0 h-5 font-medium leading-none items-center uppercase border-amber-500/30 text-amber-400"
463→                        >
464→                          {v}
465→                        </Badge>
466→                      ))}
467→                    </div>
468→                  )}
469→                  <div className="prose prose-sm dark:prose-invert max-w-none rounded-md border border-border p-4">
470→                    <ReactMarkdown remarkPlugins={[remarkGfm]}>
471→                      {hasContent ? rendered : body}
472→                    </ReactMarkdown>
473→                  </div>
474→                </>
475→              );
476→            })()}
477→
478→            {/* Variables section */}
479→            {eventDef && eventDef.variables.length > 0 && (
480→              <div className="border border-border rounded-md">
481→                <button
482→                  type="button"
483→                  className="flex items-center gap-2 w-full px-3 py-2 text-sm font-medium text-muted-foreground hover:text-foreground transition-colors"
484→                  onClick={() => setVarsOpen(!varsOpen)}
485→                >
486→                  {varsOpen ? (
487→                    <ChevronDown className="h-3.5 w-3.5" />
488→                  ) : (
489→                    <ChevronRight className="h-3.5 w-3.5" />
490→                  )}
491→                  Variables ({eventDef.variables.length})
492→                </button>
493→                {varsOpen && (
494→                  <div className="px-3 pb-3 space-y-2">
495→                    {eventDef.variables.map((v) => (
496→                      <div key={v.name} className="flex items-start gap-3 text-sm">
497→                        <code className="font-mono text-xs bg-muted px-1.5 py-0.5 rounded shrink-0">
498→                          {`{{${v.name}}}`}
499→                        </code>
500→                        <span className="text-muted-foreground">{v.description}</span>
501→                        {v.example && (
502→                          <span className="text-xs text-muted-foreground/60 shrink-0">
503→                            e.g. {v.example}
504→                          </span>
505→                        )}
506→                      </div>
507→                    ))}
508→                  </div>
509→                )}
510→              </div>
511→            )}
512→          </div>
513→        </TabsContent>
514→
515→        {/* History Tab */}
516→        <TabsContent value="history" className="flex-1 min-h-0">
517→          <DataGrid
518→            rowData={history}
519→            columnDefs={historyColumns}
520→            onRowClicked={onHistoryRowClicked}
521→            emptyMessage="No version history"
522→            pagination={false}
523→          />
524→        </TabsContent>
525→      </Tabs>
526→
527→      {/* Delete Confirmation */}
528→      <AlertDialog open={deleteOpen} onOpenChange={setDeleteOpen}>
529→        <AlertDialogContent>
530→          <AlertDialogHeader>
531→            <AlertDialogTitle>Delete template?</AlertDialogTitle>
532→            <AlertDialogDescription>
533→              This will permanently delete this template override. The default template will be used
534→              instead.
535→            </AlertDialogDescription>
536→          </AlertDialogHeader>
537→          <AlertDialogFooter>
538→            <AlertDialogCancel>Cancel</AlertDialogCancel>
539→            <AlertDialogAction className="bg-red-600 hover:bg-red-700" onClick={handleDelete}>
540→              Delete
541→            </AlertDialogAction>
542→          </AlertDialogFooter>
543→        </AlertDialogContent>
544→      </AlertDialog>
545→
546→      {/* Reset Confirmation */}
547→      <AlertDialog open={resetOpen} onOpenChange={setResetOpen}>
548→        <AlertDialogContent>
549→          <AlertDialogHeader>
550→            <AlertDialogTitle>Reset template?</AlertDialogTitle>
551→            <AlertDialogDescription>
552→              This will reset the template to its default body. Your current changes will be lost.
553→            </AlertDialogDescription>
554→          </AlertDialogHeader>
555→          <AlertDialogFooter>
556→            <AlertDialogCancel>Cancel</AlertDialogCancel>
557→            <AlertDialogAction onClick={handleReset}>Reset</AlertDialogAction>
558→          </AlertDialogFooter>
559→        </AlertDialogContent>
560→      </AlertDialog>
561→
562→      {/* Checkout Confirmation */}
563→      <AlertDialog
564→        open={checkoutVersion !== null}
565→        onOpenChange={(open) => {
566→          if (!open) setCheckoutVersion(null);
567→        }}
568→      >
569→        <AlertDialogContent>
570→          <AlertDialogHeader>
571→            <AlertDialogTitle>Checkout version {checkoutVersion}?</AlertDialogTitle>
572→            <AlertDialogDescription>
573→              This will restore the template body from version {checkoutVersion}. A new version will
574→              be created.
575→            </AlertDialogDescription>
576→          </AlertDialogHeader>
577→          <AlertDialogFooter>
578→            <AlertDialogCancel>Cancel</AlertDialogCancel>
579→            <AlertDialogAction onClick={handleCheckout}>Checkout</AlertDialogAction>
580→          </AlertDialogFooter>
581→        </AlertDialogContent>
582→      </AlertDialog>
583→    </div>
584→  );
585→}
